import { useState } from "react";
import { useNavigate } from "react-router-dom";

import { loginUser } from "../../api/authApi";
import { useAuth } from "../../context/AuthContext";

function Login() {

  const navigate = useNavigate();

  const { login } = useAuth();

  const [email, setEmail] =
    useState("");

  const [password, setPassword] =
    useState("");

  const [loading, setLoading] =
    useState(false);

  const handleSubmit =
    async (e) => {

      e.preventDefault();

      setLoading(true);

      try {

        const data =
          await loginUser({
            email,
            password
          });

        login(
          data.user,
          data.token
        );

        alert(
          "Login Successful"
        );

        if (
          data.user.role ===
          "faculty"
        ) {

          navigate(
            "/faculty/dashboard"
          );

        }

