          data.user.role ===
          "hod"
        ) {

          navigate(
            "/hod/dashboard"
          );

        }

        else if (
          data.user.role ===
          "dean"
        ) {

          navigate(
            "/dean/dashboard"
          );

        }

        else if (
          data.user.role ===
          "admin"
        ) {

          navigate(
            "/admin/dashboard"
          );

        }

      } catch (error) {

        alert(
          error.response?.data?.message ||
          "Login Failed"
        );

      } finally {

        setLoading(false);

      }
    };

  return (
    <div
      style={{
        width: "400px",
        margin: "50px auto",
        padding: "20px",
        border: "1px solid #ddd",
        borderRadius: "8px"
      }}
